// Updated UserRole enum
export enum UserRole {
    Admin = 'Admin',
    User = 'User', // Consolidated Submitter and Talent into User
}

// Example of how to update the user role checks in the codebase
@Injectable()
export class UserService {
    constructor(private readonly userRepository: UserRepository) {}

    async getUserRole(userId: string): Promise<UserRole> {
        const user = await this.userRepository.findById(userId);
        if (!user) {
            throw new NotFoundException('User not found');
        }
        return user.role; // This will now return User for both Submitter and Talent
    }

    async isUserAdmin(userId: string): Promise<boolean> {
        const role = await this.getUserRole(userId);
        return role === UserRole.Admin;
    }
}

// Example of a test for the updated user role functionality
describe('UserService', () => {
    let userService: UserService;
    let userRepository: UserRepository;

    beforeEach(() => {
        userRepository = new UserRepository();
        userService = new UserService(userRepository);
    });

    it('should return User role for Submitter', async () => {
        jest.spyOn(userRepository, 'findById').mockResolvedValue({ role: UserRole.User });
        const role = await userService.getUserRole('submitterId');
        expect(role).toBe(UserRole.User);
    });

    it('should return User role for Talent', async () => {
        jest.spyOn(userRepository, 'findById').mockResolvedValue({ role: UserRole.User });
        const role = await userService.getUserRole('talentId');
        expect(role).toBe(UserRole.User);
    });

    it('should return Admin role for Admin user', async () => {
        jest.spyOn(userRepository, 'findById').mockResolvedValue({ role: UserRole.Admin });
        const role = await userService.getUserRole('adminId');
        expect(role).toBe(UserRole.Admin);
    });

    it('should throw NotFoundException for non-existent user', async () => {
        jest.spyOn(userRepository, 'findById').mockResolvedValue(null);
        await expect(userService.getUserRole('nonExistentId')).rejects.toThrow(NotFoundException);
    });
});
